#nullable enable // autogenerated

using MVZ2.GameContent.Effects;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using MVZ2Logic.Entities;
using PVZEngine.Buffs;
using PVZEngine.Collisions;
using PVZEngine.Collisions.Level;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using PVZEngine.Modifiers;
using UnityEngine;

namespace MVZ2.GameContent.Buffs.Contraptions
{
    [AutoBuffDefinition(VanillaBuffNames.Contraption.elasticCloudEvocation)]
    public class ElasticCloudEvocationBuff : BuffDefinition
    {
        public ElasticCloudEvocationBuff(string nsp, string name) : base(nsp, name)
        {
            AddModifier(new BooleanModifier(EngineEntityProps.INVINCIBLE, true));
            AddModifier(new FloatModifier(EngineEntityProps.GRAVITY, NumberOperator.Multiply, 3));
        }
        public override void PostUpdate(Buff buff)
        {
            base.PostUpdate(buff);
            var entity = buff.GetEntity();
            if (entity == null)
                return;
            if (entity.IsOnGround)
            {
                var center = entity.Position;
                var faction = entity.GetFaction();
                var radius = 200f;
                var level = entity.Level;
                var overlapParam = OverlapParams.Hostile(faction, EntityCollisionHelper.MASK_VULNERABLE | EntityCollisionHelper.MASK_PROJECTILE);
                foreach (IEntityCollider entityCollider in level.OverlapSphere(center, radius, overlapParam))
                {
                    if (!entityCollider.IsMainCollider())
                        continue;
                    var target = entityCollider.Entity;
                    if (target.Type == EntityTypes.ENEMY)
                    {
                        var knockbackMultiplier = target.GetStrongKnockbackMultiplier();
                        target.Velocity += entity.GetFacingDirection() * (10 * knockbackMultiplier) + Vector3.up * (20 * knockbackMultiplier);

                        target.ApplyStrongImpact();
                    }
                    else if (target.Type == EntityTypes.PROJECTILE)
                    {
                        // ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝไตฏ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝำช๏ฟฝ๏ฟฝฮช๏ฟฝ๏ฟฝสต๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝำช๏ฟฝ๏ฟฝ
                        var velocity = target.GetFacingDirection() * target.Velocity.magnitude;
                        target.Velocity = velocity;
                        target.SetFaction(entity.GetFaction());
                    }
                }
                Explosion.Spawn(entity, center, radius);
                entity.PlaySound(VanillaSoundID.explosion);
                entity.DestroyConflictGridEntities();
                buff.Remove();
            }
        }
    }
}
